// Schema normalization for Source 1: Kaggle breach data
// Maps Information is Beautiful "World's Biggest Data Breaches" → unified schema

const allItems = $input.all();
const normalized = [];
const collectedAt = new Date().toISOString();

allItems.forEach((item, index) => {
  const raw = item.json;

  // Skip the metadata row (it starts with "visualisation here:")
  const orgName = String(raw['organisation'] || '').trim();
  if (orgName.toLowerCase().startsWith('visualisation here') || orgName === '') {
    return; // skip this row
  }

  // Year column has trailing spaces in source CSV — handle gracefully
  const yearRaw = raw['year   '] || raw['year'] || '';
  const year = String(yearRaw).trim();

  // Date: source has a "date" column with values like "Nov 2018"
  // For schema we standardize to YYYY-MM-DD; if only year known, use Jan 1
  let date = '';
  if (year && /^\d{4}$/.test(year)) {
    date = `${year}-01-01`;
  }

  // Severity: map the 1–5 data sensitivity scale to our enum
  const sensitivityRaw = raw['data sensitivity'];
  let severity = 'N/A';
  const s = parseInt(sensitivityRaw, 10);
  if (s === 5) severity = 'Critical';
  else if (s === 4) severity = 'High';
  else if (s === 3) severity = 'Medium';
  else if (s === 2) severity = 'Low';
  else if (s === 1) severity = 'Low';

  // Records lost — clean up text like "3m", "4m", "unknown"
  const recordsLostRaw = String(raw['records lost'] || '').trim();

  // Source URLs
  const sourceUrl = raw['1st source link'] || raw['2nd source link'] || '';

  // Description from the story column + structured context
  const story = String(raw['story'] || '').trim();
  const method = String(raw['method'] || '').trim();
  const sector = String(raw['sector'] || '').trim();
  const description = story
    ? story.slice(0, 500) // cap to 500 chars
    : `${method} breach in ${sector} sector affecting ${orgName}`;

  // Quality flags — track what's missing
  const qualityFlags = [];
  if (!year) qualityFlags.push('missing_year');
  if (!sector) qualityFlags.push('missing_sector');
  if (!method) qualityFlags.push('missing_method');
  if (severity === 'N/A') qualityFlags.push('missing_severity');
  if (!sourceUrl) qualityFlags.push('missing_source_url');

  normalized.push({
    json: {
      record_id: `BREACH-${year || 'XXXX'}-${String(index).padStart(4, '0')}`,
      source: 'kaggle_breaches',
      source_type: 'historical_breach',
      collected_at: collectedAt,
      date: date,
      entity: orgName,
      category: 'third-party',
      severity: severity,
      description: description,
      raw_url: sourceUrl,
      quality_flags: qualityFlags,
      details: {
        records_lost_raw: recordsLostRaw,
        sector: sector,
        breach_method: method,
        year: year,
        sensitivity_score: isNaN(s) ? null : s
      }
    }
  });
});

return normalized;

// Schema normalization for Source 3: CISA RSS feed
// Live cybersecurity advisories normalized into the unified schema

const allItems = $input.all();
const normalized = [];
const collectedAt = new Date().toISOString();

allItems.forEach((item, index) => {
  const raw = item.json;

  const title = String(raw.title || '').trim();
  const link = String(raw.link || '').trim();

  // Date: prefer isoDate, fall back to pubDate
  const dateRaw = raw.isoDate || raw.pubDate || raw.date || '';
  let date = '';
  try {
    if (dateRaw) {
      const d = new Date(dateRaw);
      if (!isNaN(d.getTime())) {
        date = d.toISOString().split('T')[0];
      }
    }
  } catch (e) {
    date = '';
  }

  // Description: strip HTML, cap at 500 chars
  let description = String(raw.contentSnippet || raw.content || raw.summary || '').trim();
  description = description.replace(/<[^>]*>/g, '').trim();
  if (description.length > 500) {
    description = description.slice(0, 500) + '...';
  }
  if (!description) description = title;

  // Severity heuristic — CISA advisories vary; bump on critical keywords
  let severity = 'Medium';
  const titleLower = title.toLowerCase();
  const descLower = description.toLowerCase();
  if (titleLower.includes('critical') || descLower.includes('critical') ||
      titleLower.includes('actively exploited') || descLower.includes('actively exploited') ||
      titleLower.includes('zero-day') || titleLower.includes('emergency')) {
    severity = 'High';
  }

  // Entity — try to extract vendor from title
  let entity = 'CISA';
  if (title.includes(':')) {
    entity = title.split(':').slice(1).join(':').trim().split(' ')[0] || 'CISA';
  } else {
    entity = title.split(' ')[0] || 'CISA';
  }

  // Quality flags
  const qualityFlags = [];
  if (!title) qualityFlags.push('missing_title');
  if (!date) qualityFlags.push('missing_date');
  if (!link) qualityFlags.push('missing_url');

  normalized.push({
    json: {
      record_id: `RSS-CISA-${String(index).padStart(4, '0')}`,
      source: 'rss_cisa',
      source_type: 'live_advisory',
      collected_at: collectedAt,
      date: date,
      entity: entity,
      category: 'cisa',
      severity: severity,
      description: description,
      raw_url: link,
      quality_flags: qualityFlags,
      details: {
        title: title,
        feed: 'cisa',
        original_pub_date: dateRaw,
        creator: raw.creator || raw.author || 'CISA',
        categories: raw.categories || []
      }
    }
  });
});

return normalized;

// Schema normalization for Source 2: Kaggle dataset catalog (via Kaggle API)
// Each Kaggle dataset record becomes one record in the unified schema

const allItems = $input.all();
const normalized = [];
const collectedAt = new Date().toISOString();

allItems.forEach((item, index) => {
  const raw = item.json;

  // Handle Kaggle's "Nullable" suffix on field names — strip it
  // Most fields come as titleNullable, subtitleNullable, etc.
  const title = String(raw.titleNullable || raw.title || '').trim();
  const subtitle = String(raw.subtitleNullable || raw.subtitle || '').trim();
  const creatorName = String(raw.creatorNameNullable || raw.creatorName || '').trim();
  const ownerName = String(raw.ownerNameNullable || raw.ownerName || '').trim();
  const ownerRef = String(raw.ownerRefNullable || raw.ownerRef || '').trim();
  const url = String(raw.urlNullable || raw.url || '').trim();
  const licenseName = String(raw.licenseNameNullable || raw.licenseName || '').trim();
  const ref = String(raw.ref || '').trim();
  const totalBytes = raw.totalBytesNullable || raw.totalBytes || 0;
  const usabilityRating = raw.usabilityRatingNullable || raw.usabilityRating || 0;

  // Entity = the dataset creator/owner
  const entity = creatorName || ownerName || 'Unknown';

  // Date: Kaggle returns lastUpdated as ISO timestamp
  const dateRaw = raw.lastUpdatedNullable || raw.lastUpdated || '';
  let date = '';
  try {
    if (dateRaw) {
      const d = new Date(dateRaw);
      if (!isNaN(d.getTime())) {
        date = d.toISOString().split('T')[0]; // YYYY-MM-DD
      }
    }
  } catch (e) {
    date = '';
  }

  // Severity: derived from usability rating (Kaggle's 0-1 dataset quality score)
  // Higher usability = higher confidence = used as proxy for "reference value"
  let severity = 'N/A';
  if (usabilityRating >= 0.9) severity = 'High';
  else if (usabilityRating >= 0.7) severity = 'Medium';
  else if (usabilityRating > 0) severity = 'Low';

  // Description: combine subtitle with metadata
  let description = subtitle;
  if (!description) {
    description = `Kaggle dataset by ${entity} (${ref})`;
  }
  if (description.length > 500) {
    description = description.slice(0, 500) + '...';
  }

  // Quality flags
  const qualityFlags = [];
  if (!title) qualityFlags.push('missing_title');
  if (!date) qualityFlags.push('missing_date');
  if (!url) qualityFlags.push('missing_url');
  if (!subtitle) qualityFlags.push('missing_description');
  if (severity === 'N/A') qualityFlags.push('missing_severity');

  normalized.push({
    json: {
      record_id: `KAGGLE-${String(index).padStart(4, '0')}`,
      source: 'kaggle_api',
      source_type: 'control_catalog',
      collected_at: collectedAt,
      date: date,
      entity: entity,
      category: 'cybersecurity_dataset',
      severity: severity,
      description: description,
      raw_url: url,
      quality_flags: qualityFlags,
      details: {
        dataset_title: title,
        subtitle: subtitle,
        creator: creatorName,
        owner: ownerName,
        owner_ref: ownerRef,
        kaggle_ref: ref,
        license: licenseName,
        total_bytes: totalBytes,
        usability_rating: usabilityRating,
        original_last_updated: dateRaw
      }
    }
  });
});

return normalized;

// Dedupe and finalize the merged dataset
// Composite key: (source + entity + date) — catches re-runs and overlapping records

const allItems = $input.all();
const seen = new Set();
const deduped = [];
let duplicateCount = 0;

allItems.forEach((item) => {
  const r = item.json;

  // Build composite key — handle missing fields gracefully
  const key = [
    String(r.source || 'unknown'),
    String(r.entity || 'unknown'),
    String(r.date || 'unknown'),
    String(r.record_id || '')  // record_id makes the key truly unique within a source
  ].join('||').toLowerCase();

  if (seen.has(key)) {
    duplicateCount++;
    return; // skip duplicate
  }
  seen.add(key);
  deduped.push({ json: r });
});

// Log dedupe stats for visibility
console.log(`Dedupe: ${allItems.length} input → ${deduped.length} unique (${duplicateCount} duplicates removed)`);

return deduped;

// Tag each record as 'clean' or 'rejects' based on quality flags
// We'll split into two outputs using an IF node downstream

const allItems = $input.all();
const result = [];

allItems.forEach((item) => {
  const r = item.json;
  const flags = Array.isArray(r.quality_flags) ? r.quality_flags : [];

  // Add a branch tag — clean if no flags, rejects if any flags
  r._branch = flags.length === 0 ? 'clean' : 'rejects';

  result.push({ json: r });
});

return result;
